package com.example.controller;

import com.example.model.Comment;
import com.example.service.CommentService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.owasp.html.PolicyFactory;
import org.owasp.html.Sanitizers;

import java.util.List;
import java.util.stream.Collectors;

@Controller
@RequestMapping("/comments")
public class CommentController {

    @Autowired
    private CommentService commentService;

    private static final PolicyFactory POLICY = Sanitizers.FORMATTING
            .and(Sanitizers.BLOCKS)
            .and(Sanitizers.LINKS);

    @GetMapping
    public String displayComments(Model model) {
        List<Comment> comments = commentService.getAllComments();
        
        List<Comment> sanitizedComments = comments.stream()
                .map(this::sanitizeComment)
                .collect(Collectors.toList());
        
        model.addAttribute("comments", sanitizedComments);
        return "comments";
    }

    private Comment sanitizeComment(Comment comment) {
        Comment sanitized = new Comment();
        sanitized.setId(comment.getId());
        sanitized.setUsername(comment.getUsername());
        sanitized.setContent(POLICY.sanitize(comment.getContent()));
        sanitized.setCreatedAt(comment.getCreatedAt());
        return sanitized;
    }
}